class AccessToken(db.Model):
    """Stores issued access tokens."""
    __tablename__ = 'access_tokens'

    id = db.Column(db.Integer, primary_key=True)
    token_hash = db.Column(db.String(256), unique=True, nullable=False, index=True)
    client_id = db.Column(db.Integer, db.ForeignKey('oauth_clients.id'), nullable=False)
    scopes = db.Column(db.String(512), default='')  # Space-separated scopes
    expires_at = db.Column(db.DateTime, nullable=False)
    is_revoked = db.Column(db.Boolean, default=False, nullable=False)
    created_at = db.Column(db.DateTime, default=lambda: datetime.now(timezone.utc))
    last_used_at = db.Column(db.DateTime, nullable=True)

    # Optional: track which user/resource owner the token is for
    user_id = db.Column(db.String(256), nullable=True)

    def __repr__(self):
        return f'<AccessToken id={self.id} revoked={self.is_revoked}>'

    @property
    def is_expired(self):
        return datetime.now(timezone.utc) > self.expires_at.replace(tzinfo=timezone.utc)

    @property
    def is_valid(self):
        return not self.is_revoked and not self.is_expired and self.client.is_active

    @property
    def scope_list(self):
        if not self.scopes:
            return []
        return self.scopes.strip().split()

    def has_scope(self, scope):
        return scope in self.scope_list


