# --- Token Utility Functions ---

def hash_token(token):
    """Hash a token for secure storage and lookup."""
    return hashlib.sha256(token.encode('utf-8')).hexdigest()


def generate_access_token():
    """Generate a cryptographically secure random token."""
    return secrets.token_urlsafe(48)


def create_access_token(client_id, scopes=None, user_id=None, expires_in=3600):
    """
    Create and store a new access token.
    Returns the raw token string (only available at creation time).
    """
    client = OAuthClient.query.filter_by(client_id=client_id, is_active=True).first()
    if not client:
        return None, "Client not found or inactive"

    raw_token = generate_access_token()
    token_hash_value = hash_token(raw_token)

    token = AccessToken(
        token_hash=token_hash_value,
        client_id=client.id,
        scopes=' '.join(scopes) if scopes else '',
        user_id=user_id,
        expires_at=datetime.now(timezone.utc) + timedelta(seconds=expires_in),
    )
    db.session.add(token)
    db.session.commit()

    return raw_token, None


def validate_token(raw_token):
    """
    Validate an access token by checking if it exists in the database,
    is not expired, and is not revoked.
    Returns (AccessToken, error_string).
    """
    token_hash_value = hash_token(raw_token)
    token = AccessToken.query.filter_by(token_hash=token_hash_value).first()

    if token is None:
        return None, "invalid_token"

    if token.is_revoked:
        return None, "token_revoked"

    if token.is_expired:
        return None, "token_expired"

    if not token.client.is_active:
        return None, "client_inactive"

    # Update last used timestamp
    token.last_used_at = datetime.now(timezone.utc)
    db.session.commit()

    return token, None


def extract_bearer_token(request_obj):
    """Extract the Bearer token from the Authorization header."""
    auth_header = request_obj.headers.get('Authorization', '')
    if auth_header.startswith('Bearer '):
        return auth_header[7:].strip()

    # Also check query parameter as fallback (not recommended for production)
    token = request_obj.args.get('access_token')
    if token:
        return token.strip()

    return None


def log_audit(token_hash, result, details=None):
    """Log a token validation attempt."""
    audit = TokenAuditLog(
        token_hash=token_hash,
        endpoint=request.path,
        method=request.method,
        ip_address=request.remote_addr,
        result=result,
        details=details,
    )
    db.session.add(audit)
    db.session.commit()


# --- Decorators ---

def require_oauth(*required_scopes):
    """
    Decorator to protect API endpoints with OAuth 2.0 token validation.
    
    Usage:
        @require_oauth()               # Just requires a valid token
        @require_oauth('read')          # Requires 'read' scope
        @require_oauth('read', 'write') # Requires both 'read' AND 'write' scopes
    """
    def decorator(f):
        @functools.wraps(f)
        def decorated_function(*args, **kwargs):
            # Extract token from request
            raw_token = extract_bearer_token(request)
            if not raw_token:
                log_audit(None, 'missing', 'No bearer token provided')
                return jsonify({
                    'error': 'missing_token',
                    'error_description': 'Access token is required. Provide it via Authorization: Bearer <token> header.',
                }), 401

            token_hash_value = hash_token(raw_token)

            # Validate token
            token, error = validate_token(raw_token)
            if error:
                log_audit(token_hash_value, error)

                status_code = 401
                error_description = {
                    'invalid_token': 'The access token is invalid.',
                    'token_revoked': 'The access token has been revoked.',
                    'token_expired': 'The access token has expired.',
                    'client_inactive': 'The client associated with this token is inactive.',
                }.get(error, 'Token validation failed.')

                response = jsonify({
                    'error': error,
                    'error_description': error_description,
                })
                response.headers['WWW-Authenticate'] = f'Bearer error="{error}"'
                return response, status_code

            # Check required scopes
            if required_scopes:
                missing_scopes = [s for s in required_scopes if not token.has_scope(s)]
                if missing_scopes:
                    log_audit(
                        token_hash_value,
                        'insufficient_scope',
                        f'Missing scopes: {", ".join(missing_scopes)}'
                    )
                    response = jsonify({
                        'error': 'insufficient_scope',
                        'error_description': f'Required scope(s): {", ".join(required_scopes)}. Missing: {", ".join(missing_scopes)}.',
                    })
                    response.headers['WWW-Authenticate'] = (
                        f'Bearer error="insufficient_scope", scope="{" ".join(required_scopes)}"'
                    )
                    return response, 403

            # Token is valid — set context for the endpoint
            g.current_token = token
            g.current_client = token.client
            g.current_user_id = token.user_id

            log_audit(token_hash_value, 'success')

            return f(*args, **kwargs)

        return decorated_function
    return decorator


