# -- Token Introspection Endpoint (RFC 7662) --

@app.route('/api/v1/introspect', methods=['POST'])
def introspect_token():
    """
    Token introspection endpoint per RFC 7662.
    Allows microservices to check token validity.
    """
    # In production, this endpoint itself should be authenticated
    # (e.g., via client credentials). For simplicity, we use a shared secret.
    introspect_secret = os.environ.get('INTROSPECT_SECRET', 'introspect-secret-change-me')
    provided_secret = request.form.get('client_secret') or request.headers.get('X-Introspect-Secret')

    if provided_secret != introspect_secret:
        return jsonify({'error': 'unauthorized'}), 401

    raw_token = request.form.get('token')
    if not raw_token:
        return jsonify({'active': False})

    token, error = validate_token(raw_token)
    if error:
        return jsonify({'active': False})

    return jsonify({
        'active': True,
        'scope': token.scopes,
        'client_id': token.client.client_id,
        'user_id': token.user_id,
        'exp': int(token.expires_at.replace(tzinfo=timezone.utc).timestamp()),
        'iat': int(token.created_at.replace(tzinfo=timezone.utc).timestamp()) if token.created_at else None,
    })


