@app.route('/api/v1/admin/tokens', methods=['POST'])
@require_oauth('admin')
def issue_token():
    """
    Issue a new access token for a client.
    In a real system, this would be handled by an authorization server.
    """
    data = request.get_json()
    if not data or 'client_id' not in data:
        return jsonify({'error': 'client_id is required'}), 400

    scopes = data.get('scopes', [])
    user_id = data.get('user_id')
    expires_in = data.get('expires_in', 3600)

    raw_token, error = create_access_token(
        client_id=data['client_id'],
        scopes=scopes,
        user_id=user_id,
        expires_in=expires_in,
    )

    if error:
        return jsonify({'error': error}), 400

    return jsonify({
        'access_token': raw_token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'scopes': scopes,
        'message': 'Store this token securely. It cannot be retrieved again.',
    }), 201


@app.route('/api/v1/admin/tokens/revoke', methods=['POST'])
@require_oauth('admin')
def revoke_token():
    """Revoke an access token."""
    data = request.get_json()
    if not data or 'token' not in data:
        return jsonify({'error': 'token is required'}), 400

    token_hash_value = hash_token(data['token'])
    token = AccessToken.query.filter_by(token_hash=token_hash_value).first()

    if not token:
        # Per RFC 7009, return success even if token doesn't exist
        return jsonify({'message': 'Token revoked.'})

    token.is_revoked = True
    db.session.commit()

    return jsonify({'message': 'Token revoked successfully.'})


@app.route('/api/v1/admin/audit', methods=['GET'])
@require_oauth('admin')
def get_audit_logs():
    """Get recent token audit logs."""
    limit = request.args.get('limit', 100, type=int)
    result_filter = request.args.get('result')

    query = TokenAuditLog.query.order_by(TokenAuditLog.created_at.desc())
    if result_filter:
        query = query.filter_by(result=result_filter)

    logs = query.limit(limit).all()
    return jsonify({
        'audit_logs': [
            {
                'id': log.id,
                'endpoint': log.endpoint,
                'method': log.method,
                'ip_address': log.ip_address,
                'result': log.result,
                'details': log.details,
                'created_at': log.created_at.isoformat() if log.created_at else None,
            }
            for log in logs
        ]
    })


